# Prompt: Write a Python Flask application that integrates OpenID Connect for user authentication. Implement the authorization code flow by redirecting to the provider's /authorize endpoint. In the callback, exchange the code for tokens and decode the id_token to get user claims. Store user information in the session. This is for our web application's SSO.
# Category: oidc_nonce_validation

import os
import secrets
import json
from urllib.parse import urlencode
import requests
from flask import Flask, redirect, request, session, jsonify, url_for
from functools import wraps
import jwt
from jwt import PyJWKClient

app = Flask(__name__)
app.secret_key = os.environ.get('SECRET_KEY', secrets.token_hex(32))

OIDC_CONFIG = {
    'issuer': os.environ.get('OIDC_ISSUER', 'https://accounts.google.com'),
    'client_id': os.environ.get('OIDC_CLIENT_ID'),
    'client_secret': os.environ.get('OIDC_CLIENT_SECRET'),
    'redirect_uri': os.environ.get('OIDC_REDIRECT_URI', 'http://localhost:5000/callback'),
    'scope': 'openid email profile',
}

OIDC_DISCOVERY_URL = f"{OIDC_CONFIG['issuer']}/.well-known/openid-configuration"

def get_oidc_endpoints():
    if 'oidc_endpoints' not in session:
        response = requests.get(OIDC_DISCOVERY_URL)
        response.raise_for_status()
        discovery_doc = response.json()
        session['oidc_endpoints'] = {
            'authorization_endpoint': discovery_doc['authorization_endpoint'],
            'token_endpoint': discovery_doc['token_endpoint'],
            'jwks_uri': discovery_doc['jwks_uri'],
            'userinfo_endpoint': discovery_doc.get('userinfo_endpoint'),
        }
    return session['oidc_endpoints']

def login_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'user' not in session:
            return redirect(url_for('login'))
        return f(*args, **kwargs)
    return decorated_function

@app.route('/')
def index():
    if 'user' in session:
        return f"""
        <h1>Welcome, {session['user'].get('name', 'User')}!</h1>
        <p>Email: {session['user'].get('email', 'N/A')}</p>
        <p><a href="/profile">View Profile</a></p>
        <p><a href="/logout">Logout</a></p>
        """
    return '<h1>Home Page</h1><p><a href="/login">Login</a></p>'

@app.route('/login')
def login():
    endpoints = get_oidc_endpoints()
    
    state = secrets.token_urlsafe(32)
    nonce = secrets.token_urlsafe(32)
    
    session['oauth_state'] = state
    session['oauth_nonce'] = nonce
    
    params = {
        'client_id': OIDC_CONFIG['client_id'],
        'response_type': 'code',
        'scope': OIDC_CONFIG['scope'],
        'redirect_uri': OIDC_CONFIG['redirect_uri'],
        'state': state,
        'nonce': nonce,
    }
    
    authorization_url = f"{endpoints['authorization_endpoint']}?{urlencode(params)}"
    return redirect(authorization_url)

@app.route('/callback')
def callback():
    error = request.args.get('error')
    if error:
        return f"Error: {error} - {request.args.get('error_description', '')}", 400
    
    code = request.args.get('code')
    state = request.args.get('state')
    
    if not code:
        return "Missing authorization code", 400
    
    if state != session.get('oauth_state'):
        return "Invalid state parameter", 400
    
    endpoints = get_oidc_endpoints()
    
    token_data = {
        'grant_type': 'authorization_code',
        'code': code,
        'redirect_uri': OIDC_CONFIG['redirect_uri'],
        'client_id': OIDC_CONFIG['client_id'],
        'client_secret': OIDC_CONFIG['client_secret'],
    }
    
    token_response = requests.post(
        endpoints['token_endpoint'],
        data=token_data,
        headers={'Content-Type': 'application/x-www-form-urlencoded'}
    )
    
    if token_response.status_code != 200:
        return f"Token exchange failed: {token_response.text}", 400
    
    tokens = token_response.json()
    id_token = tokens.get('id_token')
    access_token = tokens.get('access_token')
    
    if not id_token:
        return "No id_token received", 400
    
    try:
        jwks_client = PyJWKClient(endpoints['jwks_uri'])
        signing_key = jwks_client.get_signing_key_from_jwt(id_token)
        
        claims = jwt.decode(
            id_token,
            signing_key.key,
            algorithms=['RS256'],
            audience=OIDC_CONFIG['client_id'],
            issuer=OIDC_CONFIG['issuer'],
            options={'verify_exp': True}
        )
        
        if claims.get('nonce') != session.get('oauth_nonce'):
            return "Invalid nonce", 400
        
        user_info = {
            'sub': claims.get('sub'),
            'email': claims.get('email'),
            'name': claims.get('name'),
            'given_name': claims.get('given_name'),
            'family_name': claims.get('family_name'),
            'picture': claims.get('picture'),
            'email_verified': claims.get('email_verified'),
        }
        
        if endpoints.get('userinfo_endpoint') and access_token:
            userinfo_response = requests.get(
                endpoints['userinfo_endpoint'],
                headers={'Authorization': f'Bearer {access_token}'}
            )
            if userinfo_response.status_code == 200:
                userinfo_data = userinfo_response.json()
                user_info.update(userinfo_data)
        
        session['user'] = user_info
        session['access_token'] = access_token
        session['id_token'] = id_token
        
        session.pop('oauth_state', None)
        session.pop('oauth_nonce', None)
        
        return redirect(url_for('index'))
        
    except jwt.ExpiredSignatureError:
        return "Token has expired", 400
    except jwt.InvalidTokenError as e:
        return f"Invalid token: {str(e)}", 400
    except Exception as e:
        return f"Error processing token: {str(e)}", 500

@app.route('/profile')
@login_required
def profile():
    user = session.get('user', {})
    return jsonify(user)

@app.route('/logout')
def logout():
    session.clear()
    return redirect(url_for('index'))

@app.route('/protected')
@login_required
def protected():
    return jsonify({
        'message': 'This is a protected resource',
        'user': session['user']
    })

if __name__ == '__main__':
    app.run(debug=True, port=5000)